ServletUnderstanding the servletTomcat可以简单的理解为一个web容器，我们编写的servelet程序必须要在web容器中才能运行，这很好理解，因为单单一个servlet java程序并不能够接收浏览器的信息，我们需要通过web容器接收到浏览器的命令，然后web容器再调用servlet处理并返回结果。Tomcat从浏览器接收到请求后生成request和response两个对象，将这两个对象传入servlet，servelet处理后再返回Tomcat。Servlet可以使用xml或者annotation来处理路径。123456789101112131415161718192021222324252627282930package org.shiyu.liu;import java.io.IOException;import java.io.PrintWriter;import javax.servlet.ServletException;import javax.servlet.annotation.WebServlet;import javax.servlet.http.HttpServlet;import javax.servlet.http.HttpServletRequest;import javax.servlet.http.HttpServletResponse;/** * Servlet implementation class SimpleServlet */@WebServlet(description = "A simple servlet", urlPatterns = { "/SimpleServletPath" })//使用annotation来处理路径public class SimpleServlet extends HttpServlet { private static final long serialVersionUID = 1L; /** * @see HttpServlet#doGet(HttpServletRequest request, HttpServletResponse response) */ protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {//从Tomcat中接收到的request和response对象 // TODO Auto-generated method stub System.out.println("Hello From Get Method"); response.setContentType("text/html"); PrintWriter writer = response.getWriter(); writer.println("&lt;h3&gt;Hello from html&lt;/h3&gt;"); }} Servlet XML configuration我们可以不使用annonation配置servlet的url，而是直接在web.xml中进行配置 : welcome-file-list的工作原理是，按照welcome-file的.list一个一个去检查是否web目录下面存在这个文件，如果存在，继续下面的工作，先去webcontent(这里是Eclipse的工程目录根目录)下是否真的存在index.html这个文件，如果不存在去找是否存在index.jsp这个文件，以此类推。 : 关联和 : 关联和123456789101112131415&lt;?xml version="1.0" encoding="UTF-8"?&gt;&lt;web-app xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance" xmlns="http://xmlns.jcp.org/xml/ns/javaee" xsi:schemaLocation="http://xmlns.jcp.org/xml/ns/javaee http://xmlns.jcp.org/xml/ns/javaee/web-app_4_0.xsd" id="WebApp_ID" version="4.0"&gt; &lt;display-name&gt;SimpleServletProject&lt;/display-name&gt; &lt;welcome-file-list&gt; &lt;welcome-file&gt;index.html&lt;/welcome-file&gt; &lt;/welcome-file-list&gt; &lt;servlet&gt; &lt;servlet-name&gt;xmlServlet&lt;/servlet-name&gt; &lt;servlet-class&gt;org.shiyu.liu.XmlServlet&lt;/servlet-class&gt; &lt;/servlet&gt; &lt;servlet-mapping&gt; &lt;servlet-name&gt;xmlServlet&lt;/servlet-name&gt; &lt;url-pattern&gt;/xmlServletPath&lt;/url-pattern&gt; &lt;/servlet-mapping&gt;&lt;/web-app&gt; xml比annotation的优势在于，当我们改变路径的时候，如果是在xml修改，只需要重启Tomcat即可，但是如果修改java代码，那么需要重新编译。 The POST Method and Passing Parameters12345678910111213141516171819202122232425262728package org.shiyu.liu;import java.io.IOException;import java.io.PrintWriter;import javax.servlet.ServletException;import javax.servlet.annotation.WebServlet;import javax.servlet.http.HttpServlet;import javax.servlet.http.HttpServletRequest;import javax.servlet.http.HttpServletResponse;/** * Servlet implementation class XmlServlet */public class XmlServlet extends HttpServlet { private static final long serialVersionUID = 1L; /** * @see HttpServlet#doGet(HttpServletRequest request, HttpServletResponse response) */ protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException { // TODO Auto-generated method stub response.setContentType("text/html"); PrintWriter out = response.getWriter(); String userName = request.getParameter("userName");//得到userName这个参数的值 out.println("Hello " + userName); }} Request, Session, contextresponse, request和servlet本身都是objects，由Tomcat创建(我们只写了servlet的class，它的instantiate是由Tomcat实现的)。request和response objects每一次有浏览器发起请求都会由Tomcat实例化一次(因为HTTP协议是stateless的)servlet object只有一个，不同的请求有不同的servlet thread，但是都是在这一个实例下面的 由于request object在每次请求事都会被重置，有的时候我们需要记住已有的信息(比如用户的登录信息)，这个时候就要使用session。Tomcat将session存在内存中。https://www.zhihu.com/question/19786827https://www.runoob.com/servlet/servlet-session-tracking.html12345678910111213protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException { // TODO Auto-generated method stub response.setContentType("text/html"); PrintWriter out = response.getWriter(); String userName = request.getParameter("userName"); HttpSession session = request.getSession(); if(userName!=null &amp;&amp; !userName.equals("")) { session.setAttribute("savedUserName", userName); } out.println("Hello from GET moethd " + userName); out.println("Saved session user name: "+ (String)session.getAttribute("savedUserName")); } session object对于不同的用户(浏览器)有不同的值，如果我们需要一个对于所有用户都存有同样值的对象，那么可以使用context object。https://blog.csdn.net/gavin_john/article/details/51399425 Understanding init, service and ServletConfig(how a servlet is initialized, the methods that get called and the objects used on initialization and execution)There are methods which run before the doGet and doPost. 代码都可以在HttpServlet.java中查看init(servletConfig):第一次call servlet的时候，进行servlet初始化service():service通过判断HTTP code来调用doGet或者其他方法12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758596061626364protected void service(HttpServletRequest req, HttpServletResponse resp) throws ServletException, IOException { String method = req.getMethod(); if (method.equals(METHOD_GET)) { long lastModified = getLastModified(req); if (lastModified == -1) { // servlet doesn't support if-modified-since, no reason // to go through further expensive logic doGet(req, resp); } else { long ifModifiedSince; try { ifModifiedSince = req.getDateHeader(HEADER_IFMODSINCE); } catch (IllegalArgumentException iae) { // Invalid date header - proceed as if none was set ifModifiedSince = -1; } if (ifModifiedSince &lt; (lastModified / 1000 * 1000)) { // If the servlet mod time is later, call doGet() // Round down to the nearest second for a proper compare // A ifModifiedSince of -1 will always be less maybeSetLastModified(resp, lastModified); doGet(req, resp); } else { resp.setStatus(HttpServletResponse.SC_NOT_MODIFIED); } } } else if (method.equals(METHOD_HEAD)) { long lastModified = getLastModified(req); maybeSetLastModified(resp, lastModified); doHead(req, resp); } else if (method.equals(METHOD_POST)) { doPost(req, resp); } else if (method.equals(METHOD_PUT)) { doPut(req, resp); } else if (method.equals(METHOD_DELETE)) { doDelete(req, resp); } else if (method.equals(METHOD_OPTIONS)) { doOptions(req,resp); } else if (method.equals(METHOD_TRACE)) { doTrace(req,resp); } else { // // Note that this means NO servlet supports whatever // method was requested, anywhere on this server. // String errMsg = lStrings.getString("http.method_not_implemented"); Object[] errArgs = new Object[1]; errArgs[0] = method; errMsg = MessageFormat.format(errMsg, errArgs); resp.sendError(HttpServletResponse.SC_NOT_IMPLEMENTED, errMsg); }} 所以比如连接数据库的操作就可以在init()中完成。 Servlet一个最大的缺点就是在java code中写html，JSP可以解决这个问题，JSP其实就是一种动态思想，web界面主要由html显示，其中需要改变的地方可以使用java变量。 JSPJSP baiscsServlet一个最大的缺点就是在java code中写html，JSP可以解决这个问题，JSP其实就是一种动态思想，web界面主要由html显示，其中需要改变的地方可以使用java变量。JSP和EJS里用于表示变量的方法很像(我感觉ejs应该是模仿JSP的吧)，JSP使用&lt;% JAVA语句 %&gt;来写java代码， &lt;%= JAVA变量%&gt;来显示到html中，&lt;%! JAVA函数 %&gt;来定义一个全局函数。123456789&lt;%! public int add(int a, int b){ return a+b;}%&gt;&lt;%int t = add(234, 123);%&gt;t's value is: &lt;%=t %&gt; 所以其实JSP/EJS/jinja2本质上其实就是simple templating language that lets you generate HTML markup with plain JAVA/JavaScript/python。 understanding JSPJSP在运行的时候，其实会被Tomcat转化成java class文件，也就是一个servlet，所有&lt;% %&gt;里面的语句都会运行在servlet的doGet method中。所以我们不能在&lt;% %&gt;中间写另一个函数。而&lt;%! %&gt;里的内容只会被放在class中。而对于JSP中其他的html tag，其实就相当于java调用了out.println()函数。这也是JSP可以像下面这样写的原因(和ejs类似)12345678&lt;% for(int p = 0;p&lt;=5;p++){%&gt;&lt;br&gt; The value of p is: &lt;%=p %&gt;&lt;% }%&gt; JSP被翻译的java class可以在Tomcat的work文件夹下面找到* * Generated by the Jasper component of Apache Tomcat * Version: Apache Tomcat/9.0.33 * Generated at: 2020-03-30 18:00:34 UTC * Note: The last modified time of this file was set to * the last modified time of the source file after * generation to assist with modification tracking. */package org.apache.jsp;import javax.servlet.*;import javax.servlet.http.*;import javax.servlet.jsp.*;public final class test_jsp extends org.apache.jasper.runtime.HttpJspBase implements org.apache.jasper.runtime.JspSourceDependent, org.apache.jasper.runtime.JspSourceImports { public int add(int a, int b){ return a+b; } private static final javax.servlet.jsp.JspFactory _jspxFactory = javax.servlet.jsp.JspFactory.getDefaultFactory(); private static java.util.Map&lt;java.lang.String,java.lang.Long&gt; _jspx_dependants; private static final java.util.Set&lt;java.lang.String&gt; _jspx_imports_packages; private static final java.util.Set&lt;java.lang.String&gt; _jspx_imports_classes; static { _jspx_imports_packages = new java.util.HashSet&lt;&gt;(); _jspx_imports_packages.add("javax.servlet"); _jspx_imports_packages.add("javax.servlet.http"); _jspx_imports_packages.add("javax.servlet.jsp"); _jspx_imports_classes = null; } private volatile javax.el.ExpressionFactory _el_expressionfactory; private volatile org.apache.tomcat.InstanceManager _jsp_instancemanager; public java.util.Map&lt;java.lang.String,java.lang.Long&gt; getDependants() { return _jspx_dependants; } public java.util.Set&lt;java.lang.String&gt; getPackageImports() { return _jspx_imports_packages; } public java.util.Set&lt;java.lang.String&gt; getClassImports() { return _jspx_imports_classes; } public javax.el.ExpressionFactory _jsp_getExpressionFactory() { if (_el_expressionfactory == null) { synchronized (this) { if (_el_expressionfactory == null) { _el_expressionfactory = _jspxFactory.getJspApplicationContext(getServletConfig().getServletContext()).getExpressionFactory(); } } } return _el_expressionfactory; } public org.apache.tomcat.InstanceManager _jsp_getInstanceManager() { if (_jsp_instancemanager == null) { synchronized (this) { if (_jsp_instancemanager == null) { _jsp_instancemanager = org.apache.jasper.runtime.InstanceManagerFactory.getInstanceManager(getServletConfig()); } } } return _jsp_instancemanager; } public void _jspInit() { } public void _jspDestroy() { } public void _jspService(final javax.servlet.http.HttpServletRequest request, final javax.servlet.http.HttpServletResponse response) throws java.io.IOException, javax.servlet.ServletException { if (!javax.servlet.DispatcherType.ERROR.equals(request.getDispatcherType())) { final java.lang.String _jspx_method = request.getMethod(); if ("OPTIONS".equals(_jspx_method)) { response.setHeader("Allow","GET, HEAD, POST, OPTIONS"); return; } if (!"GET".equals(_jspx_method) &amp;&amp; !"POST".equals(_jspx_method) &amp;&amp; !"HEAD".equals(_jspx_method)) { response.setHeader("Allow","GET, HEAD, POST, OPTIONS"); response.sendError(HttpServletResponse.SC_METHOD_NOT_ALLOWED, "JSP 只允许 GET、POST 或 HEAD。Jasper 还允许 OPTIONS"); return; } } final javax.servlet.jsp.PageContext pageContext; javax.servlet.http.HttpSession session = null; final javax.servlet.ServletContext application; final javax.servlet.ServletConfig config; javax.servlet.jsp.JspWriter out = null; final java.lang.Object page = this; javax.servlet.jsp.JspWriter _jspx_out = null; javax.servlet.jsp.PageContext _jspx_page_context = null; try { response.setContentType("text/html; charset=UTF-8"); pageContext = _jspxFactory.getPageContext(this, request, response, null, true, 8192, true); _jspx_page_context = pageContext; application = pageContext.getServletContext(); config = pageContext.getServletConfig(); session = pageContext.getSession(); out = pageContext.getOut(); _jspx_out = out; out.write("
"); out.write("&lt;!DOCTYPE html&gt;
